import numpy as np

def find_best_route(current_node, remaining_demands, vehicle_capacity, current_load, distance_matrix, demand_list):
    n_nodes = len(remaining_demands)
    feasible_nodes = []

    # 获取所有未服务且容量可行的节点
    for node in range(n_nodes):
        if not remaining_demands[node]:
            continue
        if current_load + demand_list[node] > vehicle_capacity:
            continue
        feasible_nodes.append(node)

    if not feasible_nodes:
        return -1

    # 计算局部密度因子（每个可行节点周围未服务节点数量）
    # 使用距离阈值（所有可行节点间平均距离的一半）作为密度半径
    if len(feasible_nodes) > 1:
        avg_dist = 0
        count = 0
        for i in feasible_nodes:
            for j in feasible_nodes:
                if i != j:
                    avg_dist += distance_matrix[i, j]
                    count += 1
        threshold = avg_dist / (count * 2) if count > 0 else float('inf')
    else:
        threshold = float('inf')

    # 计算每个可行节点周围的未服务节点数（包括自身）
    total_remaining = np.sum(remaining_demands)
    density_factors = {}
    for node in feasible_nodes:
        count_dense = 0
        for other in range(n_nodes):
            if not remaining_demands[other]:
                continue
            if distance_matrix[node, other] <= threshold:
                count_dense += 1
        density_factors[node] = count_dense / total_remaining if total_remaining > 0 else 0

    # 动态权重：根据剩余节点数与需求量分布调整
    if total_remaining > 10:
        alpha = 0.3  # 容量利用率权重
        beta = 0.4   # 密度因子权重
    else:
        alpha = 0.2
        beta = 0.3

    best_node = -1
    best_score = float('inf')

    for node in feasible_nodes:
        dist = distance_matrix[current_node, node]
        capacity_ratio = demand_list[node] / vehicle_capacity if vehicle_capacity > 0 else 0
        density = density_factors[node]

        # 综合评分：距离 + α*容量利用率 - β*密度因子（密度高则评分低，更优）
        score = dist + alpha * capacity_ratio - beta * density

        if score < best_score:
            best_score = score
            best_node = node

    return best_node

