import numpy as np

def find_best_route(current_node, remaining_demands, vehicle_capacity, current_load, distance_matrix, demand_list):
    n_nodes = len(demand_list)

    # 获取所有可行候选节点（未服务且容量允许）
    feasible = np.where(remaining_demands & (current_load + demand_list <= vehicle_capacity))[0]
    if len(feasible) == 0:
        return -1
    if len(feasible) == 1:
        return int(feasible[0])

    # 预计算每个未服务节点的孤立度（到其他未服务节点的平均距离）
    unserved_indices = np.where(remaining_demands)[0]
    isolation = np.zeros(n_nodes)
    for node in unserved_indices:
        other_nodes = unserved_indices[unserved_indices != node]
        if len(other_nodes) > 0:
            isolation[node] = np.mean(distance_matrix[node, other_nodes])

    # 获取当前可行节点的孤立度
    feasible_isolation = isolation[feasible]
    avg_isolation = np.mean(feasible_isolation) if len(feasible_isolation) > 0 else 0.0

    # 容量压力判断
    remaining_cap = vehicle_capacity - current_load
    total_remaining_demand = np.sum(demand_list[unserved_indices])
    avg_demand = np.mean(demand_list[unserved_indices]) if len(unserved_indices) > 0 else 1.0
    load_ratio = current_load / vehicle_capacity if vehicle_capacity > 0 else 0.0

    # 回溯惩罚：若连续两步孤立度上升，强制选择最近节点
    if not hasattr(find_best_route, '_last_isolation'):
        find_best_route._last_isolation = None
        find_best_route._penalty_count = 0

    # 当前节点的孤立度（若可行）用于回溯判断
    current_isolation = isolation[current_node] if current_node in feasible else 0.0
    if find_best_route._last_isolation is not None:
        if current_isolation > find_best_route._last_isolation:
            find_best_route._penalty_count += 1
        else:
            find_best_route._penalty_count = 0
    find_best_route._last_isolation = current_isolation

    # 触发回溯惩罚：连续上升超过3次
    if find_best_route._penalty_count >= 3:
        find_best_route._penalty_count = 0
        # 强制选择最近节点
        dists = distance_matrix[current_node, feasible]
        best_idx = np.argmin(dists)
        return int(feasible[best_idx])

    # 容量紧张时（剩余容量 < 平均需求 * 0.6 或负载率 > 0.8），切换为最近邻
    if remaining_cap < avg_demand * 0.6 or load_ratio > 0.8:
        dists = distance_matrix[current_node, feasible]
        best_idx = np.argmin(dists)
        return int(feasible[best_idx])

    # 孤立度阈值：若某节点孤立度超过平均孤立度的1.5倍，强制优先服务
    forced_threshold = 1.5 * avg_isolation
    forced_node = -1
    for node in feasible:
        if isolation[node] >= forced_threshold:
            forced_node = node
            break
    if forced_node != -1:
        return int(forced_node)

    # 一般情况：容量充裕时，选择孤立度 × 距离最小的节点
    best_node = -1
    best_score = float('inf')
    for node in feasible:
        dist = distance_matrix[current_node, node]
        score = dist * (1 + isolation[node] / (avg_isolation + 1e-8))
        if score < best_score:
            best_score = score
            best_node = node

    return int(best_node)

import numpy as np

def find_best_route(current_node, remaining_demands, vehicle_capacity, current_load, distance_matrix, demand_list):
    n_nodes = len(demand_list)

    # 获取所有可行候选节点（未服务且容量允许）
    feasible = np.where(remaining_demands & (current_load + demand_list <= vehicle_capacity))[0]
    if len(feasible) == 0:
        return -1
    if len(feasible) == 1:
        return int(feasible[0])

    # 计算剩余容量和平均需求
    remaining_cap = vehicle_capacity - current_load
    unserved_indices = np.where(remaining_demands)[0]
    total_remaining_demand = np.sum(demand_list[unserved_indices])
    avg_demand = np.mean(demand_list[unserved_indices]) if len(unserved_indices) > 0 else 1.0

    # 预计算每个未服务节点的孤立度（到其他未服务节点的平均距离）
    isolation = np.zeros(n_nodes)
    for node in unserved_indices:
        other_nodes = unserved_indices[unserved_indices != node]
        if len(other_nodes) > 0:
            isolation[node] = np.mean(distance_matrix[node, other_nodes])

    # 计算全局平均孤立度（仅针对可行节点，用于阈值判断）
    feasible_isolation = isolation[feasible]
    avg_isolation = np.mean(feasible_isolation) if len(feasible_isolation) > 0 else 0.0

    # 容量压力系数：剩余需求总量与车辆容量的比值（越大说明容量越紧张）
    capacity_pressure = total_remaining_demand / (vehicle_capacity + 1e-8)

    # 步骤1: 检查是否有需要强制服务的孤立节点（孤立度超过平均的1.5倍）
    threshold = 1.5 * avg_isolation
    forced_node = -1
    for node in feasible:
        if isolation[node] >= threshold:
            forced_node = node
            break
    if forced_node != -1:
        return int(forced_node)

    # 步骤2: 容量紧张时切换为最近邻兜底
    if remaining_cap < avg_demand * 0.6:
        dists = distance_matrix[current_node, feasible]
        best_idx = np.argmin(dists)
        return int(feasible[best_idx])

    # 步骤3: 一般情况，选择修正距离最小的节点
    # 修正距离 = 欧氏距离 × (1 + 孤立度 × 容量压力系数)
    best_node = -1
    best_corrected_dist = float('inf')
    for node in feasible:
        dist = distance_matrix[current_node, node]
        corrected_dist = dist * (1 + isolation[node] * capacity_pressure)
        if corrected_dist < best_corrected_dist:
            best_corrected_dist = corrected_dist
            best_node = node

    return int(best_node)
